        for(uint i = 0;i < 10;i++){
            if(i == 3){
                continue ;
            }
            if(i == 5){
                break ;
            }
        }
        uint j = 10;
        while (j < 10){
            j++;
        }
    }

    function sum(uint number) external pure returns(uint){
        uint total;
        for(uint i = 0;i <= number;i++){
            total += i;
        }
        return total;
    }
}

